defmodule MyAppWeb.ProxyController do
  use MyAppWeb, :controller

  alias HTTPoison.Response

  def fetch(conn, %{"url" => url}) do
    case HTTPoison.get(url) do
      {:ok, %Response{body: body, headers: headers}} -> 
        conn |> put_resp_header("content-type", "application/json; charset=UTF-8") 
             |> send_resp(200, body)
      
      {:error, error} -> conn |> send_resp(500, "Error fetching data from the provided URL. Reason: #{inspect(error)}")
    end
  end
end